import{_ as d,o as r,c as e,ag as a}from"./chunks/framework.ePeAWSvT.js";const i="/images/image-1.png",o="/images/image-2.png",l="/images/image-3.png",n="/images/image-4.png",p="/images/image-5.png",s="/images/image-6.png",m="/images/image-7.png",g="/images/image-8.png",c="/images/image-9.png",h="/images/image-10.png",k=JSON.parse('{"title":"概述","description":"","frontmatter":{},"headers":[],"relativePath":"guide/overview/index.md","filePath":"guide/overview/index.md","lastUpdated":1772677403000}'),b={name:"guide/overview/index.md"};function P(u,t,S,_,W,y){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>为了方便网络管理员对网络设备进行操作和维护，我司特推出了设备的Web管理功能，管理员可以使用Web界面直观地对设备进行管理和维护。Web网管的运行环境如图1-1所示。</p><img src="'+i+'" alt="网管运行环境" style="display:block;margin:0 auto;"><p align="center"><em>图1-1 WEB 网管运行环境</em></p><h2 id="登录web网管" tabindex="-1">登录WEB网管 <a class="header-anchor" href="#登录web网管" aria-label="Permalink to &quot;登录WEB网管&quot;">​</a></h2><p>用户首次登录Web网管时需要使用缺省账号进行登录，登录完成后为了确保设备的安全性，需要立即更改密码，具体操作步骤如下：</p><ul><li>使用缺省账号登录Web网管</li><li>更改用户密码</li></ul><blockquote><p>📝 说明</p><ul><li>更改密码具体操作过程见用户管理5.3章节。</li></ul></blockquote><p>设备出厂时已经默认启用了Web server服务，并且有缺省的登录账号：用户名为admin、登录密码为admin，IP地址为192.168.56.166，用户可以使用这些信息完成WEB网管的首次登录。</p><p>下面以2GX8GT交换机为例，介绍如何通过Web方式登录设备，具体步骤如下：</p><img src="'+o+'" alt="Web登录界面" style="display:block;margin:0 auto;"><p align="center"><em>图1-2 WEB登录界面</em></p><ol><li>连接设备和PC，用网线将PC和设备上的以太网口（缺省情况下，所有端口均属于 VLAN 1）相连。</li><li>为PC配置IP地址，设置PC的IP地址与设备的缺省VLAN接口IP地址同网段（除设备的默认IP地址外），例如192.168.56.20。</li><li>启动浏览器，输入登录信息。</li></ol><p>在PC上启动浏览器，在地址栏中输入“192.168.56.166”后回车，进入设备的WEB登录页面，如图1-2所示。输入缺省账号“admin”、密码“admin”，单击 <strong>登录</strong> 按钮登录Web网管。系统会根据用户使用的操作系统语言来进行语言的自动选择，用户也可以进行手动切换（包括中文、English两种），如图1-3所示。</p><img src="'+l+'" alt="语言切换界面" style="display:block;margin:0 auto;"><p align="center"><em>图1-3 语言切换界面</em></p><p>为了获得更好的显示效果，推荐使用Edge、火狐Firefox或者Chrome浏览器，Chrome浏览器请升级到最新版本。</p><h2 id="web网管的退出" tabindex="-1">WEB网管的退出 <a class="header-anchor" href="#web网管的退出" aria-label="Permalink to &quot;WEB网管的退出&quot;">​</a></h2><blockquote><p>⚠️ 注意</p><ul><li>退出Web网管时，系统不会自动保存当前配置。因此建议用户在退出Web网管前先设置保存当前配置。</li></ul></blockquote><p><span style="color:red;font-size:14px;">操作步骤：</span></p><p>单击Web网管页面右上角的用户图标按钮（如图1-4所示），在弹出的对话框里单击“退出”即可退出Web网管。</p><img src="'+n+'" alt="Web网管的退出" style="display:block;margin:0 auto;"><p align="center"><em>图1-4 Web网管的退出</em></p><h2 id="日志配置" tabindex="-1">日志配置 <a class="header-anchor" href="#日志配置" aria-label="Permalink to &quot;日志配置&quot;">​</a></h2><img src="'+p+'" alt="日志配置" style="display:block;margin:0 auto;"><p align="center"><em>图1-5 日志配置</em></p><p>单击Web网管页面右上角的日志图标按钮（如图1-5所示），界面会弹出日志消息弹窗，显示设备相关日志信息，如图1-6所示。</p><p>该功能可实现设备日志的容量配置、清除和下载操作，默认日志最大容量为20条。</p><img src="'+s+'" alt="日志消息显示" style="display:block;margin:0 auto;"><p align="center"><em>图1-6 日志消息显示</em></p><h2 id="保存配置" tabindex="-1">保存配置 <a class="header-anchor" href="#保存配置" aria-label="Permalink to &quot;保存配置&quot;">​</a></h2><blockquote><p>⚠️ 注意</p><ul><li>在页面上配置完所有项目后，请务必保存配置，否则未保存的配置信息会因为重启等操作而丢失。</li></ul></blockquote><p>单击WEB网管页面右上角的保存图标按钮（如图1-7所示），即可将当前的配置保存到配置文件中，配置在重启或掉电重启后依然有效。</p><img src="'+m+'" alt="保存配置" style="display:block;margin:0 auto;"><p align="center"><em>图1-7 保存配置</em></p><p>保存配置有两种情况：</p><ol><li>在当前配置界面单击【确定】或【应用】按钮，即把当前的配置保存到内存中。此时的保存并不是把配置项真正的保存到配置文件中，若是此时交换机出现断电等故障时，则界面的配置失效。</li><li>单击导航栏下方的【保存】按钮，则系统会自动的把所有的页面的配置保存到配置文件中。</li></ol><h2 id="重启设备" tabindex="-1">重启设备 <a class="header-anchor" href="#重启设备" aria-label="Permalink to &quot;重启设备&quot;">​</a></h2><blockquote><p>⚠️ 注意</p><ul><li>重启设备前请务必保存配置，否则重启后，未保存的配置将会全部丢失。</li><li>设备重启后，用户需重新登录设备。</li></ul></blockquote><p>步骤1：单击WEB网管页面右上角的用户图标按钮（如图1-8所示），在弹出的对话框里单击“重启”按钮。</p><img src="'+g+'" alt="重启界面" style="display:block;margin:0 auto;"><p align="center"><em>图1-8 重启界面</em></p><p>步骤2：单击【确定】按钮或者等待倒计时结束，设备进入重启状态。设备重启需要一定时间，请耐心等待。</p><img src="'+c+'" alt="重启等待界面" style="display:block;margin:0 auto;"><p align="center"><em>图1-9 重启等待界面</em></p><h2 id="web管理页面布局介绍" tabindex="-1">WEB管理页面布局介绍 <a class="header-anchor" href="#web管理页面布局介绍" aria-label="Permalink to &quot;WEB管理页面布局介绍&quot;">​</a></h2><p>如图1-10所示，WEB管理主页面共分为：导航栏、辅助区、配置区三部分，各部分功能描述如表1-1所示。</p><table tabindex="0"><thead><tr><th><div style="width:80px;">配置项</div></th><th>说明</th></tr></thead><tbody><tr><td>导航栏</td><td>以导航树的形式组织设备的Web网管功能菜单，用户在导航栏中可以方便的选择功能菜单，选择结果显示在配置区中</td></tr><tr><td>辅助区</td><td>用于搜索、语言切换、告警信息提示、保存、退出、重启等操作。</td></tr><tr><td>配置区</td><td>用户进行配置和查看的区域</td></tr></tbody></table><p align="center"><em>表1-1 WEB布局说明</em></p><img src="'+h+'" alt="WEB管理主页面" style="display:block;margin:0 auto;"><p align="center"><em>图1-10 Web管理主页面</em></p><table tabindex="0"><thead><tr><th><div style="width:180px;">（1）导航栏 </div></th><th><div style="width:180px;">（2）辅助区 </div></th><th><div style="width:180px;">（3）配置区 </div></th></tr></thead></table><h2 id="web管理功能介绍" tabindex="-1">WEB管理功能介绍 <a class="header-anchor" href="#web管理功能介绍" aria-label="Permalink to &quot;WEB管理功能介绍&quot;">​</a></h2><p>Web网管功能的具体说明如表1-2所示。</p><p><strong>表1-2 WEB 网管功能说明</strong></p><table tabindex="0"><thead><tr><th>菜单/页签</th><th>菜单/页签</th><th>菜单/页签</th><th>功能说明</th></tr></thead><tbody><tr><td>监控</td><td>概况</td><td>概况</td><td>显示设备的MAC地址，序列号，软硬件版本， CPU占用率，运 行时间等状态，显示端口的link状态，端口的流量。</td></tr><tr><td>监控</td><td>端口统计</td><td>端口统计</td><td>显示端口的计数</td></tr><tr><td>监控</td><td>环路保护</td><td>环路保护</td><td>显示设备的环路保护状态</td></tr><tr><td>监控</td><td>安全</td><td>安全</td><td>显示设备的安全类相关状态</td></tr><tr><td>监控</td><td>PoE状态</td><td>PoE状态</td><td>显示设备PoE供电状态</td></tr><tr><td>监控</td><td>串口服务器状态</td><td>串口服务器状态</td><td>显示设备的串口服务器工作状态</td></tr><tr><td>监控</td><td>LLDP状态</td><td>LLDP状态</td><td>显示设备的LLDP工作状态</td></tr><tr><td>监控</td><td>IGMP Snooping状态</td><td>IGMP Snooping状态</td><td>显示设备IGMP Snooping状态</td></tr><tr><td>监控</td><td>DHCP Snooping状态</td><td>DHCP Snooping状态</td><td>显示设备DHCP Snooping状态</td></tr><tr><td>监控</td><td>QinQ信息</td><td>QinQ信息</td><td>显示设备QinQ状态</td></tr><tr><td>监控</td><td>环路检测状态</td><td>环路检测状态</td><td>显示端口环路状态</td></tr><tr><td>监控</td><td>MAC地址表</td><td>MAC地址表</td><td>显示MAC地址表信息</td></tr><tr><td>监控</td><td>ARP/邻居信息</td><td>ARP/邻居信息</td><td>显示端口ARP/邻居信息</td></tr><tr><td>监控</td><td>NTP状态</td><td>NTP状态</td><td>显示设备NTP信息</td></tr><tr><td>配置</td><td>VLAN</td><td>VLAN</td><td>新建、修改、删除VLAN，配置端口属性、VLAN归属</td></tr><tr><td>配置</td><td>端口</td><td>端口配置</td><td>设置端口的相关属性</td></tr><tr><td>配置</td><td>端口</td><td>端口扩展</td><td>设置端口限速、风暴抑制、端口隔离</td></tr><tr><td>配置</td><td>端口</td><td>端口镜像</td><td>设置/删除端口的镜像</td></tr><tr><td>配置</td><td>端口</td><td>端口聚合</td><td>设置/删除聚合口</td></tr><tr><td>配置</td><td>端口</td><td>端口违例</td><td>设置端口违例规则</td></tr><tr><td>配置</td><td>生成树</td><td>生成树</td><td>设置STP、RSTP、MSTP功能</td></tr><tr><td>配置</td><td>ERPS</td><td>ERPS</td><td>设置ERPS单环，相切环，相交环</td></tr><tr><td>配置</td><td>PoE</td><td>PoE</td><td>设置PoE功率，非标模式，使能/关闭PoE端口供电</td></tr><tr><td>配置</td><td>安全</td><td>端口安全</td><td>配置、删除端口安全功能</td></tr><tr><td>配置</td><td>安全</td><td>IP Source Guard</td><td>配置、删除IP Source Guard 功能</td></tr><tr><td>配置</td><td>安全</td><td>Dot1x</td><td>配置802.1X认证</td></tr><tr><td>配置</td><td>安全</td><td>MAC认证</td><td>配置MAC认证概况</td></tr><tr><td>配置</td><td>安全</td><td>RADIUS</td><td>配置RADIUS服务器</td></tr><tr><td>配置</td><td>控制</td><td>串口服务器</td><td>配置串口服务器</td></tr><tr><td>配置</td><td>控制</td><td>IO控制</td><td>配置DI，DO</td></tr><tr><td>配置</td><td>环路检测</td><td>环路检测</td><td>配置端口环路检测功能</td></tr><tr><td>配置</td><td>DNS</td><td>DNS</td><td>配置设备DNS功能</td></tr><tr><td>高级</td><td>二层</td><td>LLDP配置</td><td>配置、删除设备的LLDP功能</td></tr><tr><td>高级</td><td>二层</td><td>IGMP Snooping配置</td><td>显示/配置IGMP Snooping</td></tr><tr><td>高级</td><td>二层</td><td>MAC配置</td><td>配置设备的MAC地址管理模式</td></tr><tr><td>高级</td><td>二层</td><td>DHCP Snooping配置</td><td>配置设备的DHCP Snooping功能</td></tr><tr><td>高级</td><td>二层</td><td>QinQ配置</td><td>配置设备的QinQ功能</td></tr><tr><td>高级</td><td>安全</td><td>ACL配置</td><td>配置设备的ACL功能</td></tr><tr><td>高级</td><td>安全</td><td>QoS配置</td><td>配置设备的QoS功能</td></tr><tr><td>高级</td><td>安全</td><td>DoS配置</td><td>配置设备的DoS功能</td></tr><tr><td>高级</td><td>三层</td><td>ARP/邻居配置</td><td>配置ARP/邻居功能</td></tr><tr><td>高级</td><td>三层</td><td>静态路由</td><td>配置静态路由</td></tr><tr><td>维护</td><td>系统配置</td><td>系统配置</td><td>设置设备的电子标签、开启/关闭Telnet、 SSH、HTTP、HTTPS 功能，设置管理IP</td></tr><tr><td>维护</td><td>文件管理</td><td>文件管理</td><td>固件升级管理，配置管理，证书管理，页面包管理</td></tr><tr><td>维护</td><td>用户管理</td><td>用户管理</td><td>创建/删除用户，设置用户密码</td></tr><tr><td>维护</td><td>时间管理</td><td>时间管理</td><td>显示/设置系统当前日期和时间</td></tr><tr><td>维护</td><td>SNMP</td><td>SNMP</td><td>新建、修改、删除SNMP配置</td></tr><tr><td>维护</td><td>Syslog服务器</td><td>Syslog服务器</td><td>新建、编辑、删除Syslog服务器</td></tr><tr><td>诊断</td><td>网络工具</td><td>网络工具</td><td>执行ping/trace route操作并显示执行结果</td></tr><tr><td>诊断</td><td>光模块信息</td><td>光模块信息</td><td>查看光模块信息，如厂家信息，序列号，光功率等</td></tr><tr><td>诊断</td><td>一键收集</td><td>一键收集</td><td>生成诊断信息文件，并将文件打开查看或保存到本地主机</td></tr><tr><td>诊断</td><td>掉电告警</td><td>掉电告警</td><td>开启/关闭dying gasp掉电告警功能</td></tr><tr><td>诊断</td><td>线缆检测</td><td>线缆检测</td><td>检测电口线缆状态</td></tr></tbody></table>',57)])])}const q=d(b,[["render",P]]);export{k as __pageData,q as default};
